def get_direction_detail(zone_code: str) -> dict[str, str]:
    """取得特定方位的詳細 Vastu 解讀。

    Args:
        zone_code: 方位代碼（如 ``"NE"``、``"N"``）。

    Returns:
        包含方位完整解讀資訊的字典。若找不到，回傳空字典。
    """
    return dict(DIRECTION_DETAILS.get(zone_code, {}))


